using BCrypt.Net;
using Microsoft.EntityFrameworkCore; using MyCompanyApp.Domain.Entities;  namespace MyCompanyApp.Persistence.Seed;  public static class DbSeeder {     public static async Task SeedAsync(AppDbContext context, CancellationToken cancellationToken = default)     {         await context.Database.EnsureCreatedAsync(cancellationToken);          var adminRole = await context.Roles             .FirstOrDefaultAsync(role => role.Name == "Administrator", cancellationToken);          if (adminRole is null)         {             adminRole = new Role             {                 Name = "Administrator"             };              context.Roles.Add(adminRole);             await context.SaveChangesAsync(cancellationToken);         }          var adminUser = await context.Users             .FirstOrDefaultAsync(user => user.Username == "admin", cancellationToken);          if (adminUser is null)         {             adminUser = new User             {                 Username = "admin",                 PasswordHash = BCrypt.Net.BCrypt.HashPassword("Admin123"),                 IsActive = true             };              context.Users.Add(adminUser);             await context.SaveChangesAsync(cancellationToken);         }          var hasAdminRole = await context.UserRoles             .AnyAsync(userRole => userRole.UserId == adminUser.Id && userRole.RoleId == adminRole.Id, cancellationToken);          if (!hasAdminRole)         {             context.UserRoles.Add(new UserRole             {                 UserId = adminUser.Id,                 RoleId = adminRole.Id             });              await context.SaveChangesAsync(cancellationToken);         }     } }


